import Data.List

dvojkove = 1:[ 2 ^ x | x <- dvojkove ]
trojkove = 1:[ 3 ^ x | x <- trojkove ]
petkove = 1:[ 5 ^ x | x <- petkove ]

_dva_tri_bez_prvej = tail (merge dvojkove trojkove)
_dva_tri_pat = tail (tail (merge dvojkove (merge trojkove petkove)))


merge [] x     = x  
merge x []     = x
merge l1@(a:b) l2@(c:d) = if a < c then a:(merge b l2)
                            else c:(merge l1 d)

